sql:
SELECT execution_history_id
FROM test_execution_history
ORDER BY execution_history_id ASC;

SELECT test_case_version_description
FROM test_case_versions
WHERE test_case_version_id = 1;

SELECT COUNT(step_id) AS total_steps
FROM test_steps
WHERE test_id = 1;

external_knowledge:
; The hierarchical structure implies a parent-child relationship between test cases, where the top-level test cases are the ones with no parent version (i.e., `test_case_version_id` is `NULL`); 
; The execution metrics (total passes, total fails, total execution time) provide insights into the performance of each test case; 
; The access counts represent the number of times each test case was accessed by users.

sql:
SELECT parameter_value
FROM test_case_parameters
WHERE test_id = 1;
